    font-size: 13.5px;
    font-weight: 500;
    transform: translateX(120%);
    animation: slideInToast 0.3s forwards cubic-bezier(0.16, 1, 0.3, 1);
    transition: all var(--transition-fast);
}

@keyframes slideInToast {
    to { transform: translateX(0); }
}

.toast.success {
