        <div class="col-actions">
            <button type="button" class="btn-delete-row" onclick="deletePartRow(${rowId})" title="Remove row">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <polyline points="3 6 5 6 21 6"/>
                    <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>
                    <line x1="10" y1="11" x2="10" y2="17"/>
                    <line x1="14" y1="11" x2="14" y2="17"/>
                </svg>
            </button>
        </div>
    `;

    container.appendChild(rowDiv);

    // Add row to tracking state
    partRows.push({
        id: rowId,
        partNo: '',
        component: '',
        qty: 1,
        fileName: '—'
    });

    updateSummary();
}

function deletePartRow(rowId) {
    if (partRows.length === 1) {
        showToast('You must have at least one part entry.', 'error');
        return;
    }

    // Remove element
    const rowEl = document.getElementById(`part-row-${rowId}`);
    if (rowEl) rowEl.remove();

    // Remove from array
    partRows = partRows.filter(r => r.id !== rowId);

    updateSummary();
}

// ROW LOGIC ACTIONS
function handlePartChange(rowId) {
    const partSelect = document.getElementById(`part-select-${rowId}`);
    const componentInput = document.getElementById(`comp-input-${rowId}`);
    const selectedPartCode = partSelect.value;
    const customer = document.getElementById('entry-customer').value;

    const row = partRows.find(r => r.id === rowId);
    if (!row) return;

    row.partNo = selectedPartCode;

    // Lookup component name automatically
    const partsList = customerPartsMap[customer] || [];
    const partObj = partsList.find(p => p.code === selectedPartCode);
    if (partObj) {
        componentInput.value = partObj.name;
        row.component = partObj.name;
    }
}

function handleComponentChange(rowId) {
    const componentInput = document.getElementById(`comp-input-${rowId}`);
    const row = partRows.find(r => r.id === rowId);
    if (row) {
        row.component = componentInput.value;
    }
}

function handleQtyChange(rowId) {
    const qtyInput = document.getElementById(`qty-input-${rowId}`);
    let qty = parseInt(qtyInput.value) || 0;
    if (qty < 1) {
        qty = 1;
        qtyInput.value = 1;
    }

    const row = partRows.find(r => r.id === rowId);
    if (row) {
        row.qty = qty;
        updateSummary();
    }
}

// FILE ATTACHMENT SIMULATION
function triggerAttachment(rowId) {
    const fileInput = document.getElementById(`file-input-${rowId}`);
    if (fileInput) {
        fileInput.click();
    }
}

function handleFileSelected(rowId) {
    const fileInput = document.getElementById(`file-input-${rowId}`);
    const attachBtn = document.getElementById(`attach-btn-${rowId}`);
    const attachLabel = document.getElementById(`attach-label-${rowId}`);

    const row = partRows.find(r => r.id === rowId);
    if (!row) return;

    if (fileInput.files.length > 0) {
        const file = fileInput.files[0];
        row.fileName = file.name;

        attachBtn.classList.add('attached');
        attachLabel.textContent = file.name.substring(0, 10) + (file.name.length > 10 ? '...' : '');
        attachBtn.title = file.name;

        showToast(`File "${file.name}" attached successfully.`, 'success');
    } else {
        row.fileName = '—';
        attachBtn.classList.remove('attached');
        attachLabel.textContent = 'Attach';
        attachBtn.title = '';
    }
}

// CALC TOTALS SUMMARY
function updateSummary() {
    const totalRows = partRows.length;
    const totalQty = partRows.reduce((acc, row) => acc + row.qty, 0);

    const summaryText = document.getElementById('parts-summary-text');
    summaryText.textContent = `${totalRows} row${totalRows > 1 ? 's' : ''} • ${totalQty} total qty`;

    const saveBtn = document.getElementById('btn-save-entries');
    saveBtn.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/>
            <polyline points="17 21 17 13 7 13 7 21"/>
            <polyline points="7 3 7 8 15 8"/>
        </svg>
        Save ${totalRows} entr${totalRows > 1 ? 'ies' : 'y'}
    `;
}

// FORM RESET
function resetForm() {
    // Reset selections
    const customerSelect = document.getElementById('entry-customer');
    if (customerSelect) customerSelect.selectedIndex = 0;

    const hourSelect = document.getElementById('entry-hour');
    if (hourSelect) hourSelect.selectedIndex = 0;

    const shiftSelect = document.getElementById('entry-shift');
    if (shiftSelect) shiftSelect.selectedIndex = 0;

    // Clear rows container
    const container = document.getElementById('part-rows-container');
    if (container) container.innerHTML = '';

    // Reset state arrays
    partRows = [];
    rowIdCounter = 0;

    // Add first empty row
    addPartRow();
}

// SAVE ENTRIES
function saveWorkEntries(e) {
    e.preventDefault();

    const date = document.getElementById('entry-date').value;
    const shift = document.getElementById('entry-shift').value;
    const hour = document.getElementById('entry-hour').value;
    const customer = document.getElementById('entry-customer').value;

    if (!date) {
        showToast('Please select a valid date.', 'error');
        return;
    }
    if (!hour) {
        showToast('Please pick an hour slot.', 'error');
        return;
    }
    if (!customer) {
        showToast('Please select a customer.', 'error');
        return;
    }

    // Validate rows
    let validationFailed = false;
    partRows.forEach(row => {
        const partSelect = document.getElementById(`part-select-${row.id}`);
        const componentInput = document.getElementById(`comp-input-${row.id}`);
        const qtyInput = document.getElementById(`qty-input-${row.id}`);

        if (!partSelect.value) {
            showToast(`Row ${row.id}: Please select a valid Part #.`, 'error');
            validationFailed = true;
        }
        if (!componentInput.value.trim()) {
            showToast(`Row ${row.id}: Component description cannot be empty.`, 'error');
            validationFailed = true;
        }
        if (!qtyInput.value || parseInt(qtyInput.value) < 1) {
            showToast(`Row ${row.id}: Qty must be at least 1.`, 'error');
            validationFailed = true;
        }
    });

    if (validationFailed) return;

    // Compile and push data
    const newSavedCount = partRows.length;
    let newSavedQty = 0;

    partRows.forEach(row => {
        const rowId = `entry-${Date.now()}-${row.id}`;
        const process = document.getElementById(`proc-select-${row.id}`).value;
        const machine = document.getElementById(`mach-input-${row.id}`).value;
        const status = document.getElementById(`status-select-${row.id}`).value;

        const newEntry = {
            id: rowId,
            date: date,
            hour: hour,
            customer: customer,
            part: row.partNo,
            component: row.component,
            process: process,
            qty: row.qty,
            machine: machine,
            status: status,
            file: row.fileName,
            locked: false
        };

        todayEntries.push(newEntry);
        historicalEntries.unshift(newEntry); // Insert at beginning of history
        newSavedQty += row.qty;
    });

    // Update Stats counters
    todayEntriesCount += newSavedCount;
    todayQtySum += newSavedQty;

    document.getElementById('stat-today-entries').textContent = todayEntriesCount;
    document.getElementById('stat-today-qty').textContent = todayQtySum;

    // Render tables
    renderTodayEntriesTable();
    renderHistoryTable();

    // Clear and Toast
    showToast(`Successfully saved ${newSavedCount} entry/entries for shift Hour ${hour}!`);
    resetForm();
}

// RENDER TODAY'S ENTRIES TABLE
function renderTodayEntriesTable() {
    const tbody = document.getElementById('today-entries-tbody');
    tbody.innerHTML = '';

    if (todayEntries.length === 0) {
        tbody.innerHTML = `
            <tr class="empty-row-tr">
                <td colspan="8" class="empty-table-state">No entries logged for today yet.</td>
            </tr>
        `;
        return;
    }

    todayEntries.forEach(entry => {
        const tr = document.createElement('tr');

        // File Column rendering
        let fileLinkHtml = '—';
        if (entry.file !== '—') {
            fileLinkHtml = `
                <a href="#" class="table-file-link" onclick="event.preventDefault(); alert('Opening attached file: ${entry.file}');" title="${entry.file}">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48"/>
                    </svg>
                    ${entry.file.substring(0, 10)}${entry.file.length > 10 ? '...' : ''}
                </a>
            `;
        }

        tr.innerHTML = `
            <td><strong>${entry.hour}</strong></td>
            <td>${entry.customer}</td>
            <td><code>${entry.part}</code></td>
            <td>${entry.process}</td>
            <td><strong>${entry.qty}</strong></td>
            <td><span class="status-badge ${entry.status}">${entry.status.replace('-', ' ')}</span></td>
            <td>${fileLinkHtml}</td>
            <td>
                <button type="button" class="btn-delete-entry" onclick="deleteTodayEntry('${entry.id}')" title="Delete entry">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <polyline points="3 6 5 6 21 6"/>
                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>
                    </svg>
                </button>
            </td>
        `;

        tbody.appendChild(tr);
    });
}

// DELETE ENTRY FROM TODAY LIST
function deleteTodayEntry(entryId) {
    if (confirm('Are you sure you want to delete this entry?')) {
        const deletedEntryIndex = todayEntries.findIndex(e => e.id === entryId);
        if (deletedEntryIndex !== -1) {
            const entry = todayEntries[deletedEntryIndex];

            // Adjust statistics
            todayEntriesCount--;
            todayQtySum -= entry.qty;

            document.getElementById('stat-today-entries').textContent = todayEntriesCount;
            document.getElementById('stat-today-qty').textContent = todayQtySum;

            // Remove from Today's list
            todayEntries.splice(deletedEntryIndex, 1);

            // Remove from History
            historicalEntries = historicalEntries.filter(e => e.id !== entryId);

            // Re-render
            renderTodayEntriesTable();
            renderHistoryTable();

            showToast('Entry deleted successfully.', 'info');
        }
    }
}

// RENDER ALL HISTORY LIST
function renderHistoryTable() {
    const tbody = document.getElementById('history-entries-tbody');
    if (!tbody) return;

    tbody.innerHTML = '';

    // Sort logic (can filter by date, etc.)
    const fromDateVal = document.getElementById('filter-from-date').value;
    const toDateVal = document.getElementById('filter-to-date').value;

    const filtered = historicalEntries.filter(e => {
        if (!fromDateVal && !toDateVal) return true;

        const entryDate = new Date(e.date);
        let matchFrom = true;
        let matchTo = true;

        if (fromDateVal) {
            matchFrom = entryDate >= new Date(fromDateVal);
        }
        if (toDateVal) {
            matchTo = entryDate <= new Date(toDateVal);
        }
        return matchFrom && matchTo;
    });

    // Update history header count
    const totalHistEntries = filtered.length;
    const totalHistQty = filtered.reduce((acc, e) => acc + e.qty, 0);
    const summaryText = document.getElementById('history-summary-stats');
    if (summaryText) {
        summaryText.textContent = `${totalHistEntries} entry${totalHistEntries !== 1 ? 'es' : ''} • ${totalHistQty} qty`;
    }

    if (filtered.length === 0) {
        tbody.innerHTML = `
            <tr>
                <td colspan="9" class="empty-table-state">No entries found for the selected date range.</td>
            </tr>
        `;
        return;
    }

    filtered.forEach(entry => {
        const tr = document.createElement('tr');

        // File Column rendering
        let fileLinkHtml = '—';
        if (entry.file !== '—') {
            fileLinkHtml = `
                <a href="#" class="table-file-link" onclick="event.preventDefault(); alert('Opening attached file: ${entry.file}');" title="${entry.file}">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48"/>
                    </svg>
                    ${entry.file.substring(0, 15)}${entry.file.length > 15 ? '...' : ''}
                </a>
            `;
        }

        let actionColumn = '';
        if (entry.locked) {
            actionColumn = `
                <span class="lock-badge">
                    <svg viewBox="0 0 24 24" fill="currentColor">
                        <rect x="3" y="11" width="18" height="11" rx="2" ry="2" fill="none" stroke="currentColor" stroke-width="2"/>
                        <path d="M7 11V7a5 5 0 0 1 10 0v4" fill="none" stroke="currentColor" stroke-width="2"/>
                    </svg>
                    locked
                </span>
            `;
        } else {
            actionColumn = `
                <button type="button" class="btn-delete-entry" onclick="deleteTodayEntry('${entry.id}')" title="Delete entry">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <polyline points="3 6 5 6 21 6"/>
                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>
                    </svg>
                </button>
            `;
        }

        tr.innerHTML = `
            <td>${entry.date}</td>
            <td><strong>${entry.hour}</strong></td>
            <td>${entry.customer}</td>
            <td><code>${entry.part}</code></td>
            <td>${entry.process}</td>
            <td><strong>${entry.qty}</strong></td>
            <td><span class="status-badge ${entry.status}">${entry.status.replace('-', ' ')}</span></td>
            <td>${fileLinkHtml}</td>
            <td style="text-align: right; width: 100px;">${actionColumn}</td>
        `;

        tbody.appendChild(tr);
    });
}

// Add history filter listeners
document.getElementById('filter-from-date').addEventListener('change', renderHistoryTable);
document.getElementById('filter-to-date').addEventListener('change', renderHistoryTable);

