args.ReplacementContent:
    .btn-save, .btn-reset {
        width: 100%;
        justify-content: center;
    }
}

/* LIVE MONITOR TELEMETRY STYLES */
.live-monitor-content {
    display: flex;
    flex-direction: column;
    gap: 24px;
    height: 100%;
    justify-content: flex-start;
    align-content: stretch;
}

.monitor-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding-bottom: 12px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.12);
}

.live-indicator {
    display: flex;
    align-items: center;
    gap: 8px;
}

.live-dot {
    width: 8px;
    height: 8px;
    background-color: #22c55e;
    border-radius: 50%;
    box-shadow: 0 0 8px #22c55e;
}

.live-text {
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 0.08em;
    color: white;
}

.shift-badge {
    font-size: 10px;
    font-weight: 700;
    background-color: rgba(255, 255, 255, 0.1);
    padding: 4px 8px;
    border-radius: 4px;
    letter-spacing: 0.05em;
    color: rgba(255, 255, 255, 0.85);
}

.monitor-section {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.section-title {
    font-size: 9px;
    font-weight: 700;
    color: rgba(255, 255, 255, 0.4);
    letter-spacing: 0.1em;
}

/* Machine status cards grid */
.machine-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
}

.machine-card {
    background-color: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 8px;
    padding: 12px 16px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    transition: background-color var(--transition-fast);
}

.machine-card:hover {
    background-color: rgba(255, 255, 255, 0.09);
}

.machine-info {
    display: flex;
    flex-direction: column;
}

.machine-name {
    font-size: 14px;
    font-weight: 700;
    color: white;
}

.machine-status {
    font-size: 10px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.55);
    margin-top: 2px;
}

.indicator-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
}

.glow-green {
    background-color: #22c55e;
    box-shadow: 0 0 8px #22c55e;
}

.glow-amber {
    background-color: #f59e0b;
    box-shadow: 0 0 8px #f59e0b;
}

.glow-red {
    background-color: #ef4444;
    box-shadow: 0 0 8px #ef4444;
}

/* Shift Metrics grid */
.metrics-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
}

.metric-card {
    background-color: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 8px;
    padding: 14px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
}

.metric-label {
    font-size: 8px;
    font-weight: 700;
    color: rgba(255, 255, 255, 0.45);
    letter-spacing: 0.05em;
    margin-bottom: 6px;
}

.metric-value {
    font-size: 18px;
    font-weight: 800;
    color: white;
    line-height: 1.1;
}

.trend-up {
    color: #22c55e;
    font-size: 13px;
    margin-left: 2px;
}

.target-sub {
    font-size: 11px;
    color: rgba(255, 255, 255, 0.4);
    font-weight: 500;
}

/* Live Terminal Log */
.terminal-log {
    background-color: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: 8px;
    padding: 14px;
    font-family: 'Courier New', Courier, monospace;
    font-size: 11px;
    max-height: 150px;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 8px;
    box-shadow: inset 0 2px 4px rgba(0,0,0,0.15);
}

.log-line {
    color: #a7f3d0;
    line-height: 1.5;
    word-break: break-all;
    animation: fadeInLog 0.25s ease-out;
}

@keyframes fadeInLog {
    from { opacity: 0; transform: translateY(3px); }
    to { opacity: 1; transform: translateY(0); }
}

.log-time {
    color: rgba(255, 255, 255, 0.4);
    margin-right: 4px;
}

.log-tag {
    font-weight: 700;
    font-size: 9px;
    padding: 1px 4px;
    border-radius: 2px;
    margin-right: 4px;
    text-transform: uppercase;
}

.tag-success {
    background-color: rgba(34, 197, 94, 0.25);
    color: #4ade80;
    border: 1px solid rgba(34, 197, 94, 0.3);
}

.tag-system {
    background-color: rgba(59, 130, 246, 0.25);
    color: #60a5fa;
    border: 1px solid rgba(59, 130, 246, 0.3);
}

/* Animations */
@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.3; }
}

.animate-pulse {
    animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

