.animate-pulse {
    animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

/* ==========================================
   ADMIN 6-TAB CONSOLE STYLES
   ========================================== */

/* High-tech KPI and Status Grids */
.admin-stats-grid-4 {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 16px;
}

.margin-top-20 {
    margin-top: 20px;
}

.admin-stat-card-tech {
    background-color: var(--bg-white);
    border: 1px solid var(--border-color);
    border-radius: 8px;
    padding: 20px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    box-shadow: var(--shadow-sm);
    transition: transform var(--transition-fast), box-shadow var(--transition-fast);
}

.admin-stat-card-tech:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

/* Side Borders */
.border-left-green { border-left: 4.5px solid #10b981; }
.border-left-orange { border-left: 4.5px solid #f59e0b; }
.border-left-red { border-left: 4.5px solid #ef4444; }
.border-left-blue { border-left: 4.5px solid #3b82f6; }

/* Font Colors */
.font-green { color: #10b981 !important; }
.font-orange { color: #f59e0b !important; }
.font-red { color: #ef4444 !important; }
.font-blue { color: #3b82f6 !important; }

.stat-header-tech {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
}

.stat-title-tech {
    font-size: 11px;
    font-weight: 700;
    color: var(--text-light);
    letter-spacing: 0.05em;
    text-transform: uppercase;
}

.stat-icon-tech {
    width: 16px;
    height: 16px;
    color: var(--text-light);
    opacity: 0.8;
}

.stat-value-large-tech {
    font-size: 32px;
    font-weight: 800;
    color: var(--text-dark);
    line-height: 1;
}

/* Charts Elements */
.admin-charts-row {
    display: grid;
    grid-template-columns: 1.8fr 1.2fr;
    gap: 20px;
    margin-top: 24px;
}

.chart-card {
    padding: 20px;
    display: flex;
    flex-direction: column;
    height: 290px;
    justify-content: space-between;
}

.chart-header h4 {
    font-size: 11px;
    font-weight: 700;
    color: var(--text-light);
    letter-spacing: 0.08em;
}

.chart-content {
    flex: 1;
    position: relative;
    margin-top: 12px;
    width: 100%;
}

/* SVG Chart Elements */
.chart-grid-line {
    stroke: #f3f4f6;
    stroke-width: 1;
}

.chart-axis {
    stroke: #e5e7eb;
    stroke-width: 1.5;
}

.chart-line {
    fill: none;
    stroke: var(--primary-accent);
    stroke-width: 3;
    stroke-linecap: round;
}

.chart-area {
    fill: rgba(46, 125, 50, 0.05);
}

.chart-point {
    fill: white;
    stroke: var(--primary-accent);
    stroke-width: 2.5;
    cursor: pointer;
    transition: r var(--transition-fast);
}

.chart-point:hover {
    r: 6;
}

.chart-bar-bg {
    fill: #f9fafb;
    rx: 4px;
}

.chart-bar {
    fill: var(--primary-medium);
    rx: 4px;
    transition: fill var(--transition-fast);
    cursor: pointer;
}

.chart-bar:hover {
    fill: var(--primary-accent);
}

.chart-text {
    font-family: var(--font-sans);
    font-size: 10px;
    fill: var(--text-light);
    font-weight: 600;
}

/* Modals System styling */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background-color: rgba(17, 24, 39, 0.6);
    backdrop-filter: blur(4px);
    z-index: 10000;
    display: none;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.modal-overlay.active {
    display: flex;
    opacity: 1;
}

.modal-card {
    background-color: white;
    border-radius: 8px;
    width: 90%;
    max-width: 500px;
    box-shadow: var(--shadow-lg);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    transform: translateY(-20px);
    transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.modal-overlay.active .modal-card {
    transform: translateY(0);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 24px;
    border-bottom: 1px solid var(--border-color);
    background-color: #fafbfc;
}

.modal-header h3 {
    font-size: 16px;
    font-weight: 700;
    color: var(--text-dark);
}

.btn-close-modal {
    background: none;
    border: none;
    font-size: 24px;
    color: var(--text-light);
    cursor: pointer;
    line-height: 1;
}

.btn-close-modal:hover {
    color: var(--text-dark);
}

.modal-body {
    padding: 24px;
    overflow-y: auto;
    max-height: calc(100vh - 200px);
}

.modal-footer {
    padding: 16px 24px;
    border-top: 1px solid var(--border-color);
    display: flex;
    justify-content: flex-end;
    gap: 12px;
    background-color: #fafbfc;
}

.form-hint {
    font-size: 11px;
    color: var(--text-light);
    margin-top: 4px;
    display: block;
}

/* Details Modal Grid */
.details-grid {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.detail-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding-bottom: 10px;
    border-bottom: 1px dashed #f3f4f6;
}

.detail-row:last-child {
    border-bottom: none;
}

.detail-label {
    font-size: 10px;
    font-weight: 700;
    color: var(--text-light);
    letter-spacing: 0.05em;
}

.detail-val {
    font-size: 13.5px;
    font-weight: 600;
    color: var(--text-dark);
}

/* CSS iOS Toggle Switch */
.switch-toggle {
    position: relative;
    display: inline-block;
    width: 42px;
    height: 22px;
}

.switch-toggle input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider-toggle {
    position: absolute;
    cursor: pointer;
    top: 0; left: 0; right: 0; bottom: 0;
    background-color: #d1d5db;
    transition: .2s;
    border-radius: 34px;
}

.slider-toggle:before {
    position: absolute;
    content: "";
    height: 16px;
    width: 16px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    transition: .2s;
    border-radius: 50%;
    box-shadow: 0 1px 2px rgba(0,0,0,0.1);
}

input:checked + .slider-toggle {
    background-color: var(--primary-accent);
}

input:checked + .slider-toggle:before {
    transform: translateX(20px);
}

/* User role badge status */
.role-badge {
    display: inline-flex;
    align-items: center;
    padding: 3px 8px;
    border-radius: 4px;
    font-size: 10.5px;
    font-weight: 600;
    text-transform: lowercase;
}

.role-badge.employee {
    background-color: #f3f4f6;
    color: #4b5563;
    border: 1px solid #e5e7eb;
}

.role-badge.admin {
    background-color: #e6f4ea;
    color: #137333;
    border: 1px solid #a7f3d0;
}

/* All Entries Filters Grid */
.filters-grid-row {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 12px;
    align-items: flex-end;
}

.btn-reset-filters {
    width: 100%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    padding: 10px;
    background-color: white;
    border: 1px solid var(--border-color);
    border-radius: 6px;
    color: var(--text-medium);
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    transition: all var(--transition-fast);
    height: 42px;
}

.btn-reset-filters:hover {
    background-color: var(--bg-light);
    border-color: var(--text-light);
    color: var(--text-dark);
}

.btn-reset-filters svg {
    width: 14px;
    height: 14px;
}

.btn-group-reset {
    display: flex;
    align-items: flex-end;
}

.filters-search-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 16px;
    border-top: 1px solid #f3f4f6;
    padding-top: 12px;
}

.filters-search-row .search-container input {
    padding: 8px 12px;
    border: 1px solid var(--border-color);
    border-radius: 6px;
    width: 260px;
    font-size: 13px;
    font-family: var(--font-sans);
}

.filters-search-row .search-container input:focus {
    outline: none;
    border-color: var(--primary-accent);
}

/* Master Data Page Elements */
.table-search-input {
    padding: 8px 14px;
    border: 1px solid var(--border-color);
    border-radius: 6px;
    font-size: 13px;
    font-family: var(--font-sans);
    width: 240px;
    background-color: white;
}

.table-search-input:focus {
    outline: none;
    border-color: var(--primary-accent);
}

.header-action-row-horizontal {
    display: flex;
    align-items: center;
    gap: 12px;
}

.btn-add-user-header {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    background-color: var(--primary-medium);
    color: white;
    border: none;
    border-radius: 6px;
    font-size: 13px;
    font-weight: 600;
    padding: 9px 16px;
    cursor: pointer;
    transition: background-color var(--transition-fast);
}

.btn-add-user-header:hover {
    background-color: var(--primary-dark);
}

.btn-add-user-header svg {
    width: 14px;
    height: 14px;
}

/* Reports Tab Styles */
.reports-filter-card {
    padding: 20px 24px;
    margin-bottom: 24px;
}

.reports-filter-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 16px;
}

.reports-export-actions {
    display: flex;
    gap: 12px;
    margin-top: 20px;
    border-top: 1px solid var(--border-color);
    padding-top: 20px;
}

.btn-export-excel {
    background-color: #167c3b;
    color: white;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 10px 20px;
    border: none;
    border-radius: 6px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    transition: background-color var(--transition-fast);
}

.btn-export-excel:hover {
    background-color: #0f622d;
}

.btn-export-csv,
.btn-export-pdf {
    background-color: white;
    border: 1px solid var(--border-color);
    color: var(--text-medium);
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 10px 20px;
    border-radius: 6px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    transition: all var(--transition-fast);
}

.btn-export-csv:hover,
.btn-export-pdf:hover {
    background-color: var(--bg-light);
    border-color: var(--text-light);
    color: var(--text-dark);
}

.reports-header-logo {
    display: flex;
    align-items: center;
}

.reports-brand-logo {
    height: 44px;
    width: auto;
    border-radius: 4px;
    box-shadow: var(--shadow-sm);
}

.report-preview-section {
    margin-top: 28px;
}

.report-preview-section .preview-header-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
}

.report-preview-section .preview-header-row h4 {
    font-size: 11px;
    font-weight: 700;
    color: var(--text-light);
    letter-spacing: 0.08em;
}

.preview-stats-count {
    font-size: 13px;
    font-weight: 600;
    color: var(--text-medium);
}

/* Actions cell alignment */
.data-table td .btn-delete-entry {
    margin-left: 6px;
}

/* Responsive Grid Adapters for Admin Tab */
@media (max-width: 1024px) {
    .admin-stats-grid-4 {
        grid-template-columns: repeat(2, 1fr);
        gap: 12px;
    }

    .admin-charts-row {
        grid-template-columns: 1fr;
    }

    .filters-grid-row {
        grid-template-columns: repeat(4, 1fr);
    }

    .reports-filter-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 768px) {
    .admin-stats-grid-4 {
        grid-template-columns: 1fr;
        gap: 12px;
    }

    .filters-grid-row {
        grid-template-columns: 1fr;
    }

    .reports-filter-grid {
        grid-template-columns: 1fr;
    }

    .reports-export-actions {
        flex-direction: column;
    }

    .btn-export-excel, .btn-export-csv, .btn-export-pdf {
        width: 100%;
        justify-content: center;
    }
}

