// Helper: Get Current Date String (yyyy-mm-dd)
function getCurrentDateString() {
    const today = new Date();
    const yyyy = today.getFullYear();
    const mm = String(today.getMonth() + 1).padStart(2, '0');
    const dd = String(today.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
}

// ==========================================
// ROLE SWITCHING & AUTHENTICATION
// ==========================================

function switchRole(role) {
    currentRole = role;

    const tabAdmin = document.getElementById('tab-admin');
    const tabEmployee = document.getElementById('tab-employee');
    const formInstruction = document.getElementById('form-instruction');
    const labelUsername = document.getElementById('label-username');
    const inputUsername = document.getElementById('login-username');

    if (role === 'admin') {
        tabAdmin.classList.add('active');
        tabEmployee.classList.remove('active');
        formInstruction.textContent = 'LOGIN WITH ADMIN EMAIL';
        labelUsername.textContent = 'EMAIL';
        inputUsername.placeholder = 'admin@gruvfix.com';
        inputUsername.value = 'admin@gruvfix.com';
    } else {
        tabAdmin.classList.remove('active');
        tabEmployee.classList.add('active');
        formInstruction.textContent = 'LOGIN WITH EMPLOYEE ID';
        labelUsername.textContent = 'EMPLOYEE ID';
        inputUsername.placeholder = 'e.g., EMP001';
        inputUsername.value = 'EMP001';
    }
    document.getElementById('login-password').value = '';
}

function fillCreds(username, password) {
    const isEmployee = username.startsWith('EMP');
    switchRole(isEmployee ? 'employee' : 'admin');

    document.getElementById('login-username').value = username;
    document.getElementById('login-password').value = password;
    showToast('Credentials filled. Click "Sign in" to access.', 'info');
}

function handleLogin(e) {
    e.preventDefault();

    const usernameVal = document.getElementById('login-username').value.trim();
    const passwordVal = document.getElementById('login-password').value;

    // Check credentials in database
    const matchedUser = users.find(u => {
        if (currentRole === 'admin') {
            return u.email === usernameVal && u.password === passwordVal && u.role === 'admin';
        } else {
            return u.id === usernameVal && u.password === passwordVal && u.role === 'employee';
        }
    });

    if (!matchedUser) {
        showToast('Invalid credentials. Please verify your Email/ID and Password.', 'error');
        return;
    }

    if (!matchedUser.active) {
        showToast('This account has been deactivated. Please contact the administrator.', 'error');
        return;
    }

    // Login Successful
    sessionUser = matchedUser;
    isLoggedIn = true;

    if (matchedUser.role === 'admin') {
        transitionPages('login-page', 'admin-dashboard');
        switchAdminTab('dashboard');
        showToast('Welcome, System Administrator.');
    } else {
        // Employee Session Setup
        transitionPages('login-page', 'employee-dashboard');
        switchDashboardTab('new-entry');

        // Update user display tags in dashboard header
        document.querySelectorAll('.user-display-name').forEach(el => el.textContent = matchedUser.name);
        document.querySelectorAll('.user-display-id').forEach(el => el.textContent = matchedUser.id);

        // Reset counters and forms
        todayEntries = [];
        todayEntriesCount = 0;
        todayQtySum = 0;
        document.getElementById('stat-today-entries').textContent = '0';
        document.getElementById('stat-today-qty').textContent = '0';

        // Pre-populate customers list
        populateCustomersDropdown();
        resetForm();
        renderTodayEntriesTable();

        showToast(`Signed in successfully as ${matchedUser.name}.`);
    }
}

function logout() {
    isLoggedIn = false;
    sessionUser = null;
    const activeDashboard = currentRole === 'admin' ? 'admin-dashboard' : 'employee-dashboard';
    transitionPages(activeDashboard, 'login-page');
    document.getElementById('login-password').value = '';
    showToast('Logged out successfully.', 'info');
}

function transitionPages(fromPageId, toPageId) {
    const fromPage = document.getElementById(fromPageId);
    const toPage = document.getElementById(toPageId);

    fromPage.style.opacity = '0';
    fromPage.style.transform = 'translateY(-10px)';

    setTimeout(() => {
        fromPage.classList.remove('active');
        toPage.classList.add('active');

        toPage.offsetHeight; // force reflow

        toPage.style.opacity = '1';
        toPage.style.transform = 'translateY(0)';
    }, 250);
}

// TOAST SYSTEMS
function showToast(message, type = 'success') {
    const container = document.getElementById('toast-container');
    const toast = document.createElement('div');
    toast.className = `toast ${type}`;

    let iconSvg = '';
    if (type === 'success') {
        iconSvg = `<svg class="toast-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>`;
    } else if (type === 'error') {
        iconSvg = `<svg class="toast-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>`;
    } else {
        iconSvg = `<svg class="toast-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg>`;
    }

    toast.innerHTML = `${iconSvg}<span>${message}</span>`;
    container.appendChild(toast);

    setTimeout(() => {
        toast.style.transform = 'translateX(120%)';
        setTimeout(() => { toast.remove(); }, 300);
    }, 3500);
}

// ==========================================
// EMPLOYEE CONSOLE TABS & WORK LOGGING
// ==========================================

function switchDashboardTab(tabId) {
    currentTab = tabId;

    const menuNewEntry = document.getElementById('menu-new-entry');
    const menuMyHistory = document.getElementById('menu-my-history');
    const viewNewEntry = document.getElementById('view-new-entry');
    const viewMyHistory = document.getElementById('view-my-history');

    if (tabId === 'new-entry') {
        menuNewEntry.classList.add('active');
        menuMyHistory.classList.remove('active');
        viewNewEntry.classList.add('active');
        viewMyHistory.classList.remove('active');
        populateCustomersDropdown();
    } else {
        menuNewEntry.classList.remove('active');
        menuMyHistory.classList.add('active');
        viewNewEntry.classList.remove('active');
        viewMyHistory.classList.add('active');
        renderHistoryTable();
    }
}

// Dynamic Customers Dropdown Population
function populateCustomersDropdown() {
    const custSelect = document.getElementById('entry-customer');
    if (!custSelect) return;

    // Clear and add placeholder
    custSelect.innerHTML = '<option value="" disabled selected>Select customer</option>';

    customers.forEach(c => {
        const opt = document.createElement('option');
        opt.value = c.name;
        opt.textContent = c.name;
        custSelect.appendChild(opt);
    });
}

// Customer Select Trigger
function handleCustomerChange() {
    const customer = document.getElementById('entry-customer').value;

    partRows.forEach(row => {
        const partSelect = document.getElementById(`part-select-${row.id}`);
        const componentInput = document.getElementById(`comp-input-${row.id}`);

        partSelect.innerHTML = '';

        if (!customer) {
            const opt = document.createElement('option');
            opt.value = '';
            opt.textContent = 'Pick customer first';
            opt.disabled = true;
            opt.selected = true;
            partSelect.appendChild(opt);
            componentInput.value = '';
            row.partNo = '';
            row.component = '';
            return;
        }

        // Filter parts dynamically from parts master data
        const customerParts = parts.filter(p => p.customer === customer);

        const placeholderOpt = document.createElement('option');
        placeholderOpt.value = '';
        placeholderOpt.textContent = 'Select part';
        placeholderOpt.disabled = true;
        placeholderOpt.selected = !row.partNo;
        partSelect.appendChild(placeholderOpt);

        customerParts.forEach(p => {
            const opt = document.createElement('option');
            opt.value = p.partNo;
            opt.textContent = p.partNo;
            if (row.partNo === p.partNo) opt.selected = true;
            partSelect.appendChild(opt);
        });

        const hasActivePart = customerParts.some(p => p.partNo === row.partNo);
        if (!hasActivePart) {
            row.partNo = '';
            row.component = '';
            componentInput.value = '';
        }
    });
}

function handlePartChange(rowId) {
    const partSelect = document.getElementById(`part-select-${rowId}`);
    const componentInput = document.getElementById(`comp-input-${rowId}`);
    const procSelect = document.getElementById(`proc-select-${rowId}`);
    const selectedPartCode = partSelect.value;

    const row = partRows.find(r => r.id === rowId);
    if (!row) return;

    row.partNo = selectedPartCode;

    // Find part in master data
    const partObj = parts.find(p => p.partNo === selectedPartCode);
    if (partObj) {
        componentInput.value = partObj.component;
        row.component = partObj.component;

        // Auto-select process if default exists and matches option values
        if (partObj.defaultProcess && partObj.defaultProcess !== '—') {
            for (let i = 0; i < procSelect.options.length; i++) {
                if (procSelect.options[i].value.toLowerCase() === partObj.defaultProcess.toLowerCase()) {
                    procSelect.selectedIndex = i;
                    break;
                }
            }
        }
    }
}

function handleComponentChange(rowId) {
    const componentInput = document.getElementById(`comp-input-${rowId}`);
    const row = partRows.find(r => r.id === rowId);
    if (row) {
        row.component = componentInput.value;
    }
}

function handleQtyChange(rowId) {
    const qtyInput = document.getElementById(`qty-input-${rowId}`);
    let qty = parseInt(qtyInput.value) || 0;
    if (qty < 1) {
        qty = 1;
        qtyInput.value = 1;
    }

    const row = partRows.find(r => r.id === rowId);
    if (row) {
        row.qty = qty;
        updateSummary();
    }
}

// Part rows appending
function addPartRow() {
    const container = document.getElementById('part-rows-container');
    const customer = document.getElementById('entry-customer').value;
    const rowId = ++rowIdCounter;

    const rowDiv = document.createElement('div');
    rowDiv.className = 'part-row';
    rowDiv.id = `part-row-${rowId}`;

    let partOptions = '';
    if (!customer) {
        partOptions = '<option value="" disabled selected>Pick customer first</option>';
    } else {
        partOptions = '<option value="" disabled selected>Select part</option>';
        const customerParts = parts.filter(p => p.customer === customer);
        customerParts.forEach(p => {
            partOptions += `<option value="${p.partNo}">${p.partNo}</option>`;
        });
    }

    rowDiv.innerHTML = `
        <div class="col-part"><select id="part-select-${rowId}" onchange="handlePartChange(${rowId})" required>${partOptions}</select></div>
        <div class="col-comp"><input type="text" id="comp-input-${rowId}" placeholder="e.g. M10 Gasket" oninput="handleComponentChange(${rowId})" required></div>
        <div class="col-proc">
            <select id="proc-select-${rowId}" required>
                <option value="Cutting" selected>Cutting</option>
                <option value="Punching">Punching</option>
                <option value="Molding">Molding</option>
                <option value="Curing">Curing</option>
                <option value="Trimming">Trimming</option>
            </select>
        </div>
        <div class="col-qty"><input type="number" id="qty-input-${rowId}" value="1" min="1" oninput="handleQtyChange(${rowId})" required></div>
        <div class="col-mach"><input type="text" id="mach-input-${rowId}" value="CNC-03" required></div>
        <div class="col-status">
            <select id="status-select-${rowId}" required>
                <option value="completed" selected>Completed</option>
                <option value="pending">Pending</option>
                <option value="rework">Rework</option>
                <option value="hold">Hold</option>
            </select>
        </div>
        <div class="col-remarks"><input type="text" id="remarks-input-${rowId}" placeholder="Optional"></div>
        <div class="col-attach">
            <button type="button" id="attach-btn-${rowId}" class="btn-attach" onclick="triggerAttachment(${rowId})">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48"/>
                </svg>
                <span id="attach-label-${rowId}">Attach</span>
            </button>
            <input type="file" id="file-input-${rowId}" style="display: none;" onchange="handleFileSelected(${rowId})">
        </div>
        <div class="col-actions">
            <button type="button" class="btn-delete-row" onclick="deletePartRow(${rowId})">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <polyline points="3 6 5 6 21 6"/>
                    <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>
                    <line x1="10" y1="11" x2="10" y2="17"/>
                    <line x1="14" y1="11" x2="14" y2="17"/>
                </svg>
            </button>
        </div>
    `;
    container.appendChild(rowDiv);

    partRows.push({ id: rowId, partNo: '', component: '', qty: 1, fileName: '—' });
    updateSummary();
}

function deletePartRow(rowId) {
    if (partRows.length === 1) {
        showToast('You must have at least one part entry.', 'error');
        return;
    }
    const rowEl = document.getElementById(`part-row-${rowId}`);
    if (rowEl) rowEl.remove();

    partRows = partRows.filter(r => r.id !== rowId);
    updateSummary();
}

function triggerAttachment(rowId) {
    const fileInput = document.getElementById(`file-input-${rowId}`);
    if (fileInput) fileInput.click();
}

function handleFileSelected(rowId) {
    const fileInput = document.getElementById(`file-input-${rowId}`);
    const attachBtn = document.getElementById(`attach-btn-${rowId}`);
    const attachLabel = document.getElementById(`attach-label-${rowId}`);

    const row = partRows.find(r => r.id === rowId);
    if (!row) return;

    if (fileInput.files.length > 0) {
        const file = fileInput.files[0];
        row.fileName = file.name;

        attachBtn.classList.add('attached');
        attachLabel.textContent = file.name.substring(0, 10) + (file.name.length > 10 ? '...' : '');
        attachBtn.title = file.name;
        showToast(`File "${file.name}" attached.`, 'success');
    } else {
        row.fileName = '—';
        attachBtn.classList.remove('attached');
        attachLabel.textContent = 'Attach';
        attachBtn.title = '';
    }
}

function updateSummary() {
    const totalRows = partRows.length;
    const totalQty = partRows.reduce((acc, row) => acc + row.qty, 0);

    document.getElementById('parts-summary-text').textContent = `${totalRows} row${totalRows > 1 ? 's' : ''} • ${totalQty} total qty`;

    const saveBtn = document.getElementById('btn-save-entries');
    saveBtn.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/>
            <polyline points="17 21 17 13 7 13 7 21"/>
            <polyline points="7 3 7 8 15 8"/>
        </svg> Save ${totalRows} entr${totalRows > 1 ? 'ies' : 'y'}
    `;
}

function resetForm() {
    const custSelect = document.getElementById('entry-customer');
    if (custSelect) custSelect.selectedIndex = 0;

    const hourSelect = document.getElementById('entry-hour');
    if (hourSelect) hourSelect.selectedIndex = 0;

    const shiftSelect = document.getElementById('entry-shift');
    if (shiftSelect) shiftSelect.selectedIndex = 0;

    const container = document.getElementById('part-rows-container');
    if (container) container.innerHTML = '';

    partRows = [];
    rowIdCounter = 0;
    addPartRow();
}

// Save log entries by employee
function saveWorkEntries(e) {
    e.preventDefault();

    const date = document.getElementById('entry-date').value;
    const shift = document.getElementById('entry-shift').value;
    const hour = document.getElementById('entry-hour').value;
    const customer = document.getElementById('entry-customer').value;

    if (!date) { showToast('Please select a valid date.', 'error'); return; }
    if (!hour) { showToast('Please pick an hour slot.', 'error'); return; }
    if (!customer) { showToast('Please select a customer.', 'error'); return; }

    let validationFailed = false;
    partRows.forEach(row => {
        const partSelect = document.getElementById(`part-select-${row.id}`);
        const componentInput = document.getElementById(`comp-input-${row.id}`);
        const qtyInput = document.getElementById(`qty-input-${row.id}`);

        if (!partSelect.value) {
            showToast(`Row ${row.id}: Select a valid Part #.`, 'error');
            validationFailed = true;
        }
        if (!componentInput.value.trim()) {
            showToast(`Row ${row.id}: Component description cannot be empty.`, 'error');
            validationFailed = true;
        }
        if (!qtyInput.value || parseInt(qtyInput.value) < 1) {
            showToast(`Row ${row.id}: Quantity must be at least 1.`, 'error');
            validationFailed = true;
        }
    });
    if (validationFailed) return;

    const newSavedCount = partRows.length;
    let newSavedQty = 0;

    partRows.forEach(row => {
        const rowId = `entry-${Date.now()}-${row.id}`;
        const process = document.getElementById(`proc-select-${row.id}`).value;
        const machine = document.getElementById(`mach-input-${row.id}`).value;
        const status = document.getElementById(`status-select-${row.id}`).value;

        const newEntry = {
            id: rowId,
            date: date,
            hour: hour,
            shift: shift.replace(' Shift', '').charAt(0), // "Day Shift (08:00 - 20:00)" -> "D" or just shift select value character
            employee: sessionUser ? sessionUser.name : 'Ravi Kumar',
            customer: customer,
            part: row.partNo,
            component: row.component,
            process: process,
            qty: row.qty,
            machine: machine,
            status: status,
            file: row.fileName,
            locked: false
        };

        // If Shift select contains Day Shift, set shift to "A", else "B"
        if (shift.includes('Day')) {
            newEntry.shift = 'A';
        } else {
            newEntry.shift = 'B';
        }

        todayEntries.push(newEntry);
        historicalEntries.unshift(newEntry);
        newSavedQty += row.qty;
    });

    todayEntriesCount += newSavedCount;
    todayQtySum += newSavedQty;

    document.getElementById('stat-today-entries').textContent = todayEntriesCount;
    document.getElementById('stat-today-qty').textContent = todayQtySum;

    // Update live monitor statistics on login page
    shiftPartsCount += newSavedQty;
    const monitorPartsEl = document.getElementById('monitor-stat-parts');
    if (monitorPartsEl) {
        monitorPartsEl.innerHTML = `${shiftPartsCount} <span class="target-sub">/ 350</span>`;
    }
    addLiveTerminalLog(`Operator ${sessionUser ? sessionUser.id : 'EMP001'} saved ${newSavedQty} parts for ${customer} on CNC-03`, 'success');

    renderTodayEntriesTable();
    renderHistoryTable();
    showToast(`Successfully saved ${newSavedCount} work entries.`);
    resetForm();
}

