function deleteTodayEntry(entryId) {
    if (confirm('Delete this entry?')) {
        const deletedEntryIndex = todayEntries.findIndex(e => e.id === entryId);
        if (deletedEntryIndex !== -1) {
            const entry = todayEntries[deletedEntryIndex];

            todayEntriesCount--;
            todayQtySum -= entry.qty;
            document.getElementById('stat-today-entries').textContent = todayEntriesCount;
            document.getElementById('stat-today-qty').textContent = todayQtySum;

            todayEntries.splice(deletedEntryIndex, 1);
            historicalEntries = historicalEntries.filter(e => e.id !== entryId);

            renderTodayEntriesTable();
            renderHistoryTable();
            showToast('Entry deleted.', 'info');
        }
    }
}

function renderHistoryTable() {
    const tbody = document.getElementById('history-entries-tbody');
    if (!tbody) return;

    tbody.innerHTML = '';

    const fromDateVal = document.getElementById('filter-from-date').value;
    const toDateVal = document.getElementById('filter-to-date').value;

    const filtered = historicalEntries.filter(e => {
        // Only show historical entries made by current logged in employee
        const operatorName = sessionUser ? sessionUser.name : 'Ravi Kumar';
        if (!e.employee.includes(operatorName)) return false;

        if (!fromDateVal && !toDateVal) return true;

        const entryDate = new Date(e.date);
        let matchFrom = true;
        let matchTo = true;

        if (fromDateVal) matchFrom = entryDate >= new Date(fromDateVal);
        if (toDateVal) matchTo = entryDate <= new Date(toDateVal);
        return matchFrom && matchTo;
    });

    const totalHistEntries = filtered.length;
    const totalHistQty = filtered.reduce((acc, e) => acc + e.qty, 0);

    const summaryText = document.getElementById('history-summary-stats');
    if (summaryText) {
        summaryText.textContent = `${totalHistEntries} entry${totalHistEntries !== 1 ? 'es' : ''} • ${totalHistQty} qty`;
    }

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="9" class="empty-table-state">No entries found for the selected date range.</td></tr>`;
        return;
    }

    filtered.forEach(entry => {
        const tr = document.createElement('tr');

        let fileLinkHtml = '—';
        if (entry.file !== '—') {
            fileLinkHtml = `
                <a href="#" class="table-file-link" onclick="event.preventDefault(); alert('Opening attached file: ${entry.file}');">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48"/>
                    </svg>
                    ${entry.file.substring(0, 15)}${entry.file.length > 15 ? '...' : ''}
                </a>
            `;
        }

        let actionColumn = '';
        if (entry.locked) {
            actionColumn = `
                <span class="lock-badge">
                    <svg viewBox="0 0 24 24" fill="currentColor">
                        <rect x="3" y="11" width="18" height="11" rx="2" ry="2" fill="none" stroke="currentColor" stroke-width="2"/>
                        <path d="M7 11V7a5 5 0 0 1 10 0v4" fill="none" stroke="currentColor" stroke-width="2"/>
                    </svg> locked
                </span>
            `;
        } else {
            actionColumn = `
                <button type="button" class="btn-delete-entry" onclick="deleteTodayEntry('${entry.id}')" title="Delete entry">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <polyline points="3 6 5 6 21 6"/>
                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>
                    </svg>
                </button>
            `;
        }

        tr.innerHTML = `
            <td>${entry.date}</td>
            <td><strong>${entry.hour}</strong></td>
            <td>${entry.customer}</td>
            <td><code>${entry.part}</code></td>
            <td>${entry.process}</td>
            <td><strong>${entry.qty}</strong></td>
            <td><span class="status-badge ${entry.status}">${entry.status}</span></td>
            <td>${fileLinkHtml}</td>
            <td style="text-align: right; width: 100px;">${actionColumn}</td>
        `;
        tbody.appendChild(tr);
    });
}

