// SVG Line Chart Render (7-Day Trend)
function renderTrendLineChart() {
    const svg = document.getElementById('svg-trend-chart');
    if (!svg) return;
    svg.innerHTML = ''; // Clear prior SVG nodes

    // Calculate last 7 dates from today
    const dates = [];
    const dateLabels = [];
    for (let i = 6; i >= 0; i--) {
        const d = new Date();
        d.setDate(d.getDate() - i);
        const yyyy = d.getFullYear();
        const mm = String(d.getMonth() + 1).padStart(2, '0');
        const dd = String(d.getDate()).padStart(2, '0');
        dates.push(`${yyyy}-${mm}-${dd}`);

        // e.g. "Jun 13"
        const monthShort = d.toLocaleString('default', { month: 'short' });
        dateLabels.push(`${dd}-${monthShort}`);
    }

    // Calculate quantities for these 7 days
    const dailyQtys = dates.map(dt => {
        return historicalEntries.filter(e => e.date === dt).reduce((sum, e) => sum + e.qty, 0);
    });

    // Append dummy default historical values if all zeroes to ensure layout has data
    const hasData = dailyQtys.some(q => q > 0);
    if (!hasData) {
        dailyQtys[0] = 45;
        dailyQtys[1] = 65;
        dailyQtys[2] = 30;
        dailyQtys[3] = 95;
        dailyQtys[4] = 50;
        dailyQtys[5] = 110;
        dailyQtys[6] = todayQtySum; // Include operator session quantities
    }

    const maxVal = Math.max(...dailyQtys, 100);
    const heightScale = 150 / maxVal;

    // Draw grid horizontal dashed lines
    for (let i = 0; i <= 4; i++) {
        const yVal = 20 + i * 37.5;
        const gridVal = Math.round(maxVal - (i * (maxVal / 4)));
        svg.innerHTML += `
            <line class="chart-grid-line" x1="40" y1="${yVal}" x2="580" y2="${yVal}" stroke-dasharray="3,3" />
            <text class="chart-text" x="30" y="${yVal + 3}" text-anchor="end">${gridVal}</text>
        `;
    }

    // X Axis line
    svg.innerHTML += `<line class="chart-axis" x1="40" y1="170" x2="580" y2="170" />`;

    // Compute line coordinates (x, y)
    const points = [];
    for (let i = 0; i < 7; i++) {
        const x = 40 + i * 90;
        const y = 170 - (dailyQtys[i] * heightScale);
        points.push({ x, y, qty: dailyQtys[i] });
    }

    // Draw shaded area path
    let areaPath = `M ${points[0].x} 170`;
    points.forEach(p => {
        areaPath += ` L ${p.x} ${p.y}`;
    });
    areaPath += ` L ${points[points.length - 1].x} 170 Z`;
    svg.innerHTML += `<path class="chart-area" d="${areaPath}" />`;

    // Draw line path
    let linePath = `M ${points[0].x} ${points[0].y}`;
    for (let i = 1; i < points.length; i++) {
        linePath += ` L ${points[i].x} ${points[i].y}`;
    }
    svg.innerHTML += `<path class="chart-line" d="${linePath}" />`;

    // Draw dots and text tags
    points.forEach((p, idx) => {
        svg.innerHTML += `
            <circle class="chart-point" cx="${p.x}" cy="${p.y}" r="4.5" />
            <text class="chart-text" x="${p.x}" y="190" text-anchor="middle">${dateLabels[idx]}</text>
        `;

        // Value labels above nodes if > 0
        if (p.qty > 0) {
            svg.innerHTML += `
                <text class="chart-text" x="${p.x}" y="${p.y - 8}" text-anchor="middle" font-weight="700" fill="var(--primary-medium)">${p.qty}</text>
            `;
        }
    });
}

// SVG Bar Chart Render (Shift A vs B today)
function renderShiftBarChart() {
    const svg = document.getElementById('svg-shift-chart');
    if (!svg) return;
    svg.innerHTML = '';

    const todayStr = getCurrentDateString();
    const todayLogs = historicalEntries.filter(e => e.date === todayStr);

    let qtyA = todayLogs.filter(e => e.shift === 'A').reduce((sum, e) => sum + e.qty, 0);
    let qtyB = todayLogs.filter(e => e.shift === 'B').reduce((sum, e) => sum + e.qty, 0);

    // Add fallback mock values if zero to ensure beautiful graphics
    if (qtyA === 0 && qtyB === 0) {
        qtyA = 120;
        qtyB = 40;
    }

    const maxVal = Math.max(qtyA, qtyB, 100);
    const heightScale = 140 / maxVal;

    // Grid lines
    for (let i = 0; i <= 4; i++) {
        const yVal = 20 + i * 35;
        const gridVal = Math.round(maxVal - (i * (maxVal / 4)));
        svg.innerHTML += `
            <line class="chart-grid-line" x1="40" y1="${yVal}" x2="280" y2="${yVal}" stroke-dasharray="3,3" />
            <text class="chart-text" x="30" y="${yVal + 3}" text-anchor="end">${gridVal}</text>
        `;
    }

    // Baseline
    svg.innerHTML += `<line class="chart-axis" x1="40" y1="160" x2="280" y2="160" />`;

    const barWidth = 48;
    const xPosA = 80;
    const xPosB = 180;

    const heightA = qtyA * heightScale;
    const heightB = qtyB * heightScale;

    // Render Bars
    svg.innerHTML += `
        <!-- Shift A Bar -->
        <rect class="chart-bar-bg" x="${xPosA}" y="20" width="${barWidth}" height="140" />
        <rect class="chart-bar" x="${xPosA}" y="${160 - heightA}" width="${barWidth}" height="${heightA}" />
        <text class="chart-text" x="${xPosA + barWidth/2}" y="180" text-anchor="middle">Shift A</text>
        <text class="chart-text" x="${xPosA + barWidth/2}" y="${155 - heightA}" text-anchor="middle" font-weight="700" fill="white">${qtyA}</text>

        <!-- Shift B Bar -->
        <rect class="chart-bar-bg" x="${xPosB}" y="20" width="${barWidth}" height="140" />
        <rect class="chart-bar" x="${xPosB}" y="${160 - heightB}" width="${barWidth}" height="${heightB}" />
        <text class="chart-text" x="${xPosB + barWidth/2}" y="180" text-anchor="middle">Shift B</text>
        <text class="chart-text" x="${xPosB + barWidth/2}" y="${155 - heightB}" text-anchor="middle" font-weight="700" fill="white">${qtyB}</text>
    `;
}

