function resetAdminFilters() {
    document.getElementById('admin-filter-from').value = '';
    document.getElementById('admin-filter-to').value = '';
    document.getElementById('admin-filter-employee').selectedIndex = 0;
    document.getElementById('admin-filter-customer').selectedIndex = 0;
    document.getElementById('admin-filter-shift').selectedIndex = 0;
    document.getElementById('admin-filter-status').selectedIndex = 0;
    document.getElementById('admin-search-entries').value = '';

    filterAdminEntries();
}

function filterAdminEntries() {
    const fromDate = document.getElementById('admin-filter-from').value;
    const toDate = document.getElementById('admin-filter-to').value;
    const employee = document.getElementById('admin-filter-employee').value;
    const customer = document.getElementById('admin-filter-customer').value;
    const shift = document.getElementById('admin-filter-shift').value;
    const status = document.getElementById('admin-filter-status').value;
    const query = document.getElementById('admin-search-entries').value.toLowerCase().trim();

    const filtered = historicalEntries.filter(e => {
        // Date Check
        if (fromDate && new Date(e.date) < new Date(fromDate)) return false;
        if (toDate && new Date(e.date) > new Date(toDate)) return false;

        // Dropdown checks
        if (employee !== 'All' && !e.employee.includes(employee)) return false;
        if (customer !== 'All' && e.customer !== customer) return false;
        if (shift !== 'All' && e.shift !== shift) return false;
        if (status !== 'All' && e.status !== status) return false;

        // Full-text search
        if (query) {
            const matchStr = `${e.date} ${e.hour} ${e.employee} ${e.customer} ${e.part} ${e.component} ${e.process} ${e.machine} ${e.status}`.toLowerCase();
            if (!matchStr.includes(query)) return false;
        }
        return true;
    });

    const entriesCount = filtered.length;
    const totalQtySum = filtered.reduce((sum, e) => sum + e.qty, 0);

    document.getElementById('admin-entries-summary-stats').textContent = `${entriesCount} entry${entriesCount !== 1 ? 'es' : ''} • ${totalQtySum} total qty`;

    const tbody = document.getElementById('admin-entries-tbody');
    tbody.innerHTML = '';

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="12" class="empty-table-state">No entries found matching the filter criteria.</td></tr>`;
        return;
    }

    filtered.forEach(e => {
        const tr = document.createElement('tr');

        let fileLink = '—';
        if (e.file !== '—') {
            fileLink = `
                <a href="#" class="table-file-link" onclick="event.preventDefault(); alert('Opening attached file: ${e.file}');" title="${e.file}">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48"/>
                    </svg>
                    ${e.file.substring(0, 10)}${e.file.length > 10 ? '...' : ''}
                </a>
            `;
        }

        tr.innerHTML = `
            <td>${e.date}</td>
            <td><strong>${e.hour}</strong></td>
            <td>${e.shift}</td>
            <td>${e.employee.split(' (')[0]}</td>
            <td>${e.customer}</td>
            <td><code>${e.part}</code></td>
            <td>${e.component}</td>
            <td>${e.process}</td>
            <td><strong>${e.qty}</strong></td>
            <td><span class="status-badge ${e.status}">${e.status}</span></td>
            <td>${fileLink}</td>
            <td style="text-align: right; white-space: nowrap;">
                <button type="button" class="btn-reset" style="padding: 4px 8px; font-size: 11px;" onclick="openLogDetailsModal('${e.id}')">
                    open
                </button>
                <button type="button" class="btn-delete-entry" onclick="deleteAdminEntry('${e.id}')" title="Delete entry">
