function saveUserModal(e) {
    e.preventDefault();
    const index = document.getElementById('modal-user-index').value;
    const role = document.getElementById('modal-user-role').value;
    const empId = role === 'admin' ? '—' : document.getElementById('modal-user-empid').value.trim();
    const email = document.getElementById('modal-user-email').value.trim();
    const password = document.getElementById('modal-user-password').value;
    const active = document.getElementById('modal-user-active').value === 'true';

    // Simple validation
    if (role === 'employee' && !empId) {
        showToast('Employee ID is required for employee accounts.', 'error');
        return;
    }

    if (index === '') {
        // Add new user
        // Check for duplicates
        const exists = users.some(u => u.email === email || (role === 'employee' && u.id === empId));
        if (exists) {
            showToast('User with this email or Employee ID already exists.', 'error');
            return;
        }

        const newUser = { id: empId, email, password, role, active };
        if (role === 'employee') {
            newUser.name = email.split('@')[0].replace('.', ' '); // Dummy display name
        }
        users.push(newUser);
        showToast('User created successfully.');
    } else {
        // Update user
        const idxVal = parseInt(index);

        // Check duplicate email
        const duplicateEmail = users.some((u, idx) => u.email === email && idx !== idxVal);
        if (duplicateEmail) {
            showToast('Email address is already in use by another account.', 'error');
            return;
        }

        users[idxVal].email = email;
        users[idxVal].active = active;
        if (role === 'employee') {
            users[idxVal].id = empId;
        }
        if (password) {
            users[idxVal].password = password;
        }
        showToast('User profile settings updated.');
    }

    closeModal('modal-user');
    renderEmployeesTable();
}

function deleteUser(index) {
    if (confirm('Deletions are permanent. Delete this user account?')) {
        users.splice(index, 1);
        showToast('User account removed.', 'info');
        renderEmployeesTable();
