function saveCustomerModal(e) {
    e.preventDefault();
    const index = document.getElementById('modal-customer-index').value;
    const name = document.getElementById('modal-customer-name').value.trim();
    const code = document.getElementById('modal-customer-code').value.trim() || '—';
    const notes = document.getElementById('modal-customer-notes').value.trim() || '—';

    if (index === '') {
        // Create new
        const exists = customers.some(c => c.name.toLowerCase() === name.toLowerCase());
        if (exists) {
            showToast('Customer name already exists.', 'error');
            return;
        }
        customers.push({ name, code, notes });
        showToast('Customer created successfully.');
    } else {
        // Edit existing
        const idxVal = parseInt(index);
        const oldName = customers[idxVal].name;

        const duplicate = customers.some((c, idx) => c.name.toLowerCase() === name.toLowerCase() && idx !== idxVal);
        if (duplicate) {
            showToast('Customer name already in use.', 'error');
            return;
        }

        customers[idxVal].name = name;
        customers[idxVal].code = code;
        customers[idxVal].notes = notes;

        // Cascade name updates to parts list
        parts.forEach(p => {
            if (p.customer === oldName) p.customer = name;
        });

        // Cascade name updates to historical ledger
        historicalEntries.forEach(h => {
            if (h.customer === oldName) h.customer = name;
        });

        showToast('Customer details saved.');
    }

    closeModal('modal-customer');
    renderCustomersTable();
}

function deleteCustomer(index) {
