    if (confirm(`Deleting "${customerName}" will also remove all their associated parts and log references. Continue?`)) {
        customers.splice(index, 1);
        parts = parts.filter(p => p.customer !== customerName);
        historicalEntries = historicalEntries.filter(e => e.customer !== customerName);

        showToast('Customer and dependent records deleted.', 'info');
        renderCustomersTable();
    }
}

