function getFilteredReportData() {
    const fromDate = document.getElementById('report-filter-from').value;
    const toDate = document.getElementById('report-filter-to').value;
    const employee = document.getElementById('report-filter-employee').value;
    const customer = document.getElementById('report-filter-customer').value;
    const shift = document.getElementById('report-filter-shift').value;
    const status = document.getElementById('report-filter-status').value;
    const part = document.getElementById('report-filter-part').value.toLowerCase().trim();

    return historicalEntries.filter(e => {
        if (fromDate && new Date(e.date) < new Date(fromDate)) return false;
        if (toDate && new Date(e.date) > new Date(toDate)) return false;
        if (employee !== 'All' && !e.employee.includes(employee)) return false;
        if (customer !== 'All' && e.customer !== customer) return false;
        if (shift !== 'All' && e.shift !== shift) return false;
        if (status !== 'All' && e.status !== status) return false;
        if (part && !e.part.toLowerCase().includes(part)) return false;
        return true;
    });
}

function filterReportPreview() {
    const filtered = getFilteredReportData();

    const count = filtered.length;
    const qty = filtered.reduce((sum, e) => sum + e.qty, 0);

    document.getElementById('report-preview-summary-stats').textContent = `${count} entry${count !== 1 ? 'es' : ''} • ${qty} qty`;

    const tbody = document.getElementById('report-preview-tbody');
    tbody.innerHTML = '';

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="7" class="empty-table-state">No matching records found. Apply filter terms above.</td></tr>`;
        return;
    }

    filtered.forEach(e => {
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>${e.date}</td>
            <td><strong>${e.hour}</strong></td>
            <td>${e.employee.split(' (')[0]}</td>
            <td>${e.customer}</td>
            <td><code>${e.part}</code></td>
            <td><strong>${e.qty}</strong></td>
            <td><span class="status-badge ${e.status}">${e.status}</span></td>
        `;
        tbody.appendChild(tr);
    });
}

// Simulated/Actual Report Exporter
function exportReport(type) {
    const filteredData = getFilteredReportData();

    if (filteredData.length === 0) {
        showToast('No data matches the selected filters. Export aborted.', 'error');
        return;
    }

    if (type === 'csv') {
        // Build CSV Content
        let csvContent = 'Date,Hour Slot,Shift,Employee,Customer,Part Number,Component,Process,Quantity,Machine,Status,File Attachment\r\n';

        filteredData.forEach(e => {
            const rowArr = [
                e.date,
                `"${e.hour}"`,
                e.shift,
                `"${e.employee}"`,
                `"${e.customer}"`,
                `"${e.part}"`,
                `"${e.component}"`,
                `"${e.process}"`,
                e.qty,
                e.machine,
                e.status,
                e.file
            ];
            csvContent += rowArr.join(',') + '\r\n';
        });

        // Trigger CSV File Download
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        const url = URL.createObjectURL(blob);

        link.setAttribute('href', url);
        link.setAttribute('download', `gruvfix_production_report_${getCurrentDateString()}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

        showToast('CSV export downloaded successfully.');
    } else if (type === 'excel') {
        // Simulated Excel Export with CSV delivery
        let csvContent = 'Date,Hour,Shift,Employee,Customer,Part #,Component,Process,Qty,Machine,Status\n';
        filteredData.forEach(e => {
            csvContent += `${e.date},${e.hour},${e.shift},${e.employee},${e.customer},${e.part},${e.component},${e.process},${e.qty},${e.machine},${e.status}\n`;
        });
        const blob = new Blob([csvContent], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = `gruvfix_production_report_${getCurrentDateString()}.xlsx`;
        link.click();

        showToast('Excel report generated and downloaded.');
    } else if (type === 'pdf') {
        // Simulated print/PDF view
        window.print();
        showToast('PDF report compiled and sent to printer spool.', 'info');
    }
}

