}

// EMPLOYEE STATS CALCULATOR
function updateEmployeeStats() {
    if (!loggedInUser) return;
    const todayStr = getTodayDateString();

    const empTodayEntries = historicalEntries.filter(e => e.date === todayStr && e.employee === loggedInUser.empid);
    const count = empTodayEntries.length;
    const qty = empTodayEntries.reduce((sum, e) => sum + e.qty, 0);

    const countEl = document.getElementById('stat-today-entries');
    if (countEl) countEl.textContent = count;

    const qtyEl = document.getElementById('stat-today-qty');
    if (qtyEl) qtyEl.textContent = qty;
}

// 6. CUSTOMER PARTS DYNAMIC LOOKUP (EMPLOYEE FORM)
function handleCustomerChange() {
    const customerSelect = document.getElementById('entry-customer');
    const customer = customerSelect.value;

    partRows.forEach(row => {
        const partSelect = document.getElementById(`part-select-${row.id}`);
        const componentInput = document.getElementById(`comp-input-${row.id}`);

        partSelect.innerHTML = '';

        if (!customer) {
            const opt = document.createElement('option');
            opt.value = '';
            opt.textContent = 'Pick customer first';
            opt.disabled = true;
            opt.selected = true;
            partSelect.appendChild(opt);
            componentInput.value = '';
            row.partNo = '';
            row.component = '';
            return;
        }

        // Dynamic lookup from global master array
        const filteredParts = parts.filter(p => p.customer === customer);

        const placeholderOpt = document.createElement('option');
        placeholderOpt.value = '';
        placeholderOpt.textContent = 'Select part';
        placeholderOpt.disabled = true;
        placeholderOpt.selected = !row.partNo;
        partSelect.appendChild(placeholderOpt);

        filteredParts.forEach(p => {
            const opt = document.createElement('option');
            opt.value = p.partNo;
            opt.textContent = p.partNo;
            if (row.partNo === p.partNo) {
                opt.selected = true;
            }
            partSelect.appendChild(opt);
        });

        const hasActivePart = filteredParts.some(p => p.partNo === row.partNo);
        if (!hasActivePart) {
            row.partNo = '';
            row.component = '';
            componentInput.value = '';
        }
    });
}

function handlePartChange(rowId) {
    const partSelect = document.getElementById(`part-select-${rowId}`);
    const componentInput = document.getElementById(`comp-input-${rowId}`);
    const selectedPartCode = partSelect.value;
    const customer = document.getElementById('entry-customer').value;

    const row = partRows.find(r => r.id === rowId);
    if (!row) return;

    row.partNo = selectedPartCode;

    // Look up component and default process from dynamic parts master
    const partObj = parts.find(p => p.customer === customer && p.partNo === selectedPartCode);
    if (partObj) {
        componentInput.value = partObj.component;
        row.component = partObj.component;

        const procSelect = document.getElementById(`proc-select-${rowId}`);
        if (procSelect && partObj.process) {
            procSelect.value = partObj.process;
        }
    }
}

