        tr.innerHTML = `
            <td>${entry.date}</td>
            <td><strong>${entry.hour}</strong></td>
            <td>${entry.customer}</td>
            <td><code>${entry.part}</code></td>
            <td>${entry.process}</td>
            <td><strong>${entry.qty}</strong></td>
            <td><span class="status-badge ${entry.status}">${entry.status.replace('-', ' ')}</span></td>
            <td>${fileLinkHtml}</td>
